change_filament_gcode:
G92 E0
SET_VELOCITY_LIMIT ACCEL=3500
G91
G1 Z1 F480 ; move Z axis 1mm
G90 ; set all axes to absolute

; Tool change logic
{if next_extruder == 0}
  T1 ; switch to tool head T1
  ; Cleaning T1
{if layer_num % 20 == 0} 
G92 E0
BRUSH_ACTIVE_NOZZLE
{endif}
M104 S{first_layer_temperature[1] - standby_temperature_delta }
  T0 ; switch to tool head T0
  {if layer_z < 0.39}
 ;BRUSH_ACTIVE_NOZZLE
  {endif}
{else}
  T0 ; switch to tool head T0
  ; Cleaning T0
{if layer_num % 20 == 0} 
G92 E0
BRUSH_ACTIVE_NOZZLE
{endif}
M104 S{first_layer_temperature[0] - standby_temperature_delta }
  T1 ; switch to tool head T1
  {if layer_z < 0.39}
    BRUSH_ACTIVE_NOZZLE
    G91
    G92 E0
    G4 S0
    G90
  {endif}
{endif}

G91
G1 Z-1 F480 ; move Z axis 1mm
G90 ; set all axes to absolute
SET_VELOCITY_LIMIT ACCEL=2000

; Tool Change Script Ending
